@prefix cdi: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/dataset/observations-wide> ;
            sh:resultMessage "A DDI-CDI WideDataSet should specify cdi:isStructuredBy - a reference to a WideDataStructure (Required per CDIF DD Appendix 4)" ;
            sh:resultPath cdi:isStructuredBy ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A DDI-CDI WideDataSet should specify cdi:isStructuredBy - a reference to a WideDataStructure (Required per CDIF DD Appendix 4)" ;
                    sh:minCount 1 ;
                    sh:path cdi:isStructuredBy ;
                    sh:severity sh:Warning ] ] .

